function portfolioSweepHasBlockingReason(item: Web3TradingState["autonomous_portfolio_sentinel"]["items"][number]) {
  return item.blockers.some((blocker) => blocker !== "Sample mode does not request live swap routes.");
}

function portfolioSweepReadyItems(state: Web3TradingState) {
  return state.autonomous_portfolio_sentinel.items
    .filter((item) => item.recommended_release_usd >= 25 && !portfolioSweepHasBlockingReason(item))
    .sort((a, b) => b.recommended_release_usd - a.recommended_release_usd)
    .slice(0, 3);
}

function portfolioSweepWindowKey(state: Web3TradingState) {
  return [
    state.paper_account.cycle,
    Math.round(state.autonomous_portfolio_sentinel.recommended_release_usd * 100),
    ...portfolioSweepReadyItems(state).map((item) => `${item.position_id}:${item.action}:${Math.round(item.recommended_release_usd * 100)}`),
  ].join("|");
}

