        <MiniStat label="Action cap" value={reflex.max_notional_usd > 0 ? formatCurrency(reflex.max_notional_usd) : "none"} valueClassName={cn("text-sm leading-5", reflex.max_notional_usd > 0 ? "text-engine" : "text-outline")} />
