function StrategyChip({ selected }: { selected: boolean }) {
  return (
    <span
      className={cn(
        "inline-flex rounded-md border px-2 py-1 font-mono text-[11px] uppercase tracking-telemetry",
        selected
          ? "border-engine/40 bg-engine/10 text-engine"
          : "border-outline-variant/50 bg-surface-high/40 text-outline",
      )}
    >
      {selected ? "selected" : "replay"}
    </span>
  );
}

function PlanChip({ status }: { status: string }) {
  const style = {
    quoted: "border-engine/40 bg-engine/10 text-engine",
    "no-route": "border-caution/40 bg-caution/10 text-caution",
    "unsupported-chain": "border-outline-variant/50 bg-surface-high/40 text-outline",
    blocked: "border-critical/40 bg-critical/10 text-critical",
    "not-needed": "border-outline-variant/50 bg-surface-high/40 text-outline",
  }[status] ?? "border-outline-variant/50 bg-surface-high/40 text-outline";
  return (
    <span className={cn("inline-flex rounded-md border px-2 py-1 font-mono text-[11px] uppercase tracking-telemetry", style)}>
      {status.replace("-", " ")}
    </span>
  );
}

function sourceTone(status: Web3TradingState["market_source"]["status"]) {
  if (status === "live") return "engine";
  if (status === "fallback") return "caution";
  return "violet";
}

function feedIntegrityTone(status: Web3TradingState["market_feed_integrity"]["status"]) {
  if (status === "healthy" || status === "sample") return "engine";
  if (status === "degraded") return "caution";
  if (status === "stale" || status === "fallback") return "critical";
  return "neutral";
}

function marketStreamTone(status: Web3TradingState["market_stream_supervisor"]["status"]) {
  if (status === "streaming" || status === "sample") return "engine";
  if (status === "backfill") return "caution";
  if (status === "reconnect") return "critical";
  return "neutral";
}

function marketIngestionTone(status: Web3TradingState["market_ingestion_plan"]["status"]) {
  if (status === "stream-ready" || status === "sample") return "engine";
  if (status === "repair") return "caution";
  if (status === "blocked") return "critical";
  return "neutral";
}

function marketProviderBudgetTone(status: Web3TradingState["market_ingestion_plan"]["provider_budget_status"]) {
  if (status === "within-budget" || status === "paused") return "engine";
  if (status === "hot") return "caution";
  if (status === "throttled") return "critical";
  return "neutral";
}

function dexStreamFreshnessTone(status: Web3TradingState["dex_stream_freshness"]["status"]) {
  if (status === "hot" || status === "ready" || status === "sample") return "engine";
  if (status === "watch" || status === "backfill") return "caution";
  if (status === "blocked") return "critical";
  return "neutral";
}

function dexStreamFreshnessItemClass(status: Web3TradingState["dex_stream_freshness"]["items"][number]["status"]) {
  if (status === "stream-ready" || status === "sample") return "border-engine/40 bg-engine/10 text-engine";
  if (status === "poll-fallback") return "border-caution/40 bg-caution/10 text-caution";
  if (status === "blocked") return "border-critical/40 bg-critical/10 text-critical";
  return "border-outline-variant/50 bg-surface-high/40 text-outline";
}

function feedIntegrityCheckClass(status: string) {
  if (status === "pass") return "border-engine/40 bg-engine/10 text-engine";
  if (status === "watch") return "border-caution/40 bg-caution/10 text-caution";
  return "border-critical/40 bg-critical/10 text-critical";
}

function marketStreamLaneClass(status: string) {
  if (status === "subscribed" || status === "sample") return "border-engine/40 bg-engine/10 text-engine";
  if (status === "backfill") return "border-caution/40 bg-caution/10 text-caution";
  if (status === "reconnect") return "border-critical/40 bg-critical/10 text-critical";
  return "border-outline-variant/50 bg-surface-high/40 text-outline";
}

function marketIngestionStepClass(action: string) {
  if (action === "connect" || action === "sample") return "border-engine/40 bg-engine/10 text-engine";
  if (action === "poll" || action === "backfill") return "border-caution/40 bg-caution/10 text-caution";
  if (action === "reconnect") return "border-critical/40 bg-critical/10 text-critical";
  return "border-outline-variant/50 bg-surface-high/40 text-outline";
}

function marketProviderLaneClass(status: string) {
  if (status === "active" || status === "reserved") return "border-engine/40 bg-engine/10 text-engine";
  if (status === "hot") return "border-caution/40 bg-caution/10 text-caution";
  if (status === "throttled") return "border-critical/40 bg-critical/10 text-critical";
  return "border-outline-variant/50 bg-surface-high/40 text-outline";
}

function cycleNotice(payload: Web3TradingState, advanced: boolean, reset: boolean) {
  if (reset) {
    return "Paper account reset. No autonomous order was filled during reset.";
  }
  if (!advanced) {
    return payload.market_source.status === "live"
      ? "Live DEX read refreshed. No paper order was filled."
      : "Market view refreshed. No paper order was filled.";
  }
  const prefix =
    payload.market_source.status === "live"
      ? "Live DEX read complete."
      : payload.market_source.status === "fallback"
        ? "Live DEX unavailable; sample fallback loaded."
        : "Sample cycle complete.";
  const trade = payload.trade_tape.length > 0
    ? " Autonomous paper trades filled."
    : " No fresh trade cleared the gates.";
  return `${prefix}${trade}`;
}

function daemonNotice(payload: Web3TradingState) {
  if (payload.paper_daemon.status === "advanced") {
    return `Daemon advanced the paper ledger and recorded ${payload.paper_daemon.filled_count} paper fill${payload.paper_daemon.filled_count === 1 ? "" : "s"}.`;
  }
  if (payload.paper_daemon.status === "stand-down") {
    return "Daemon stood down and preserved capital. No order was signed or submitted.";
  }
  return "Daemon observed the market and kept the paper ledger unchanged.";
}

function formatCurrency(value: number) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: value > 1000 ? 0 : 2,
  }).format(value);
}

function formatSignedCurrency(value: number) {
  const normalized = Object.is(value, -0) ? 0 : value;
  return `${normalized > 0 ? "+" : ""}${formatCurrency(normalized)}`;
}

function formatCompactCurrency(value: number) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    notation: "compact",
    maximumFractionDigits: 1,
  }).format(value);
}

function formatPrice(value: number) {
  if (value < 0.01) return `$${value.toFixed(7)}`;
  if (value < 1) return `$${value.toFixed(4)}`;
  return `$${value.toFixed(2)}`;
}

function formatSignedPct(value: number) {
  return `${value >= 0 ? "+" : ""}${value.toFixed(1)}%`;
}

function formatLamportsCompact(value: number) {
  if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(value >= 10_000_000 ? 0 : 1)}M`;
  if (value >= 1_000) return `${Math.round(value / 1_000)}K`;
  return value.toString();
}

function formatQuoteAge(quotedAt: string | null, asOf: string) {
  const age = quoteAgeSeconds(quotedAt, asOf);
  return age === null ? "n/a" : `${age}s`;
}

function formatQuoteTimestamp(quotedAt: string | null) {
  if (!quotedAt) return "n/a";
  const quotedMs = Date.parse(quotedAt);
  if (!Number.isFinite(quotedMs)) return "invalid";
  return new Date(quotedMs).toISOString().slice(11, 19);
}

function quoteAgeTone(quotedAt: string | null, asOf: string, maxAgeSeconds: number) {
  const age = quoteAgeSeconds(quotedAt, asOf);
  if (age === null) return "text-outline";
  return age <= maxAgeSeconds ? "text-engine" : "text-critical";
}

function quoteAgeSeconds(quotedAt: string | null, asOf: string) {
  if (!quotedAt) return null;
  const asOfMs = Date.parse(asOf);
  const quotedMs = Date.parse(quotedAt);
  if (!Number.isFinite(asOfMs) || !Number.isFinite(quotedMs)) return null;
  return Math.max(0, Math.round((asOfMs - quotedMs) / 1_000));
}

function signedTone(value: number) {
  return value >= 0 ? "text-engine" : "text-critical";
}

function shortHash(value: string) {
  if (value.length <= 18) return value;
  return `${value.slice(0, 10)}...${value.slice(-6)}`;
}

function draftFromReadiness(state: Web3TradingState) {
  const config = state.execution_readiness.config;
  return {
    wallet_public_key: config.wallet_public_key ?? "",
    max_trade_usd: String(config.max_trade_usd),
    daily_spend_cap_usd: String(config.daily_spend_cap_usd),
    max_slippage_bps: String(config.max_slippage_bps),
    signer_session_label: config.signer_session_label,
    signer_network: config.signer_network as SignerSimulationNetwork,
  };
}
